record.field:
{
    "type": "object",
    "properties": {
        "member_name": {"type": "string", "description": "Name of the member"},
        "member_id": {"type": "integer", "description": "ID of the member"},
        "subject": {"type": "string", "description": "Email subject line"},
        "body": {"type": "string", "description": "Message body text"},
        "message": {"type": "string", "description": "Alternative for body"},
        "send_email": {"type": "boolean", "description": "Send via email", "default": true},
        "send_sms": {"type": "boolean", "description": "Send via SMS", "default": true}
    },
    "required": ["member_name", "body"]
}

{
    "type": "object",
    "properties": {
        "member_name": {"type": "string", "description": "Name of the member or contact to email"},
        "contact_name": {"type": "string", "description": "Alternative: contact/guardian name"},
        "email": {"type": "string", "description": "Email address (if not using member name)"},
        "subject": {"type": "string", "description": "Email subject line"},
        "body": {"type": "string", "description": "Email message content"}
    }
}

{
    "type": "object",
    "properties": {
        "member_name": {"type": "string", "description": "Name of the member or contact to text"},
        "contact_name": {"type": "string", "description": "Alternative: contact/guardian name"},
        "body": {"type": "string", "description": "SMS message text (keep under 160 characters)"},
        "message": {"type": "string", "description": "Alternative: message field"}
    }
}

{
    "type": "object",
    "required": ["subject", "body"],
    "properties": {
        "subject": {"type": "string", "description": "Email subject"},
        "body": {"type": "string", "description": "Email body text"},
        "membership_state": {"type": "string", "enum": ["active", "trial", "paused", "cancelled"], "description": "Filter audience by membership state (default: active)"},
        "send_now": {"type": "boolean", "description": "Send immediately (true) or save as draft (false, default)"}
    }
}

{
    "type": "object",
    "required": ["body"],
    "properties": {
        "body": {"type": "string", "description": "SMS text (keep under 160 chars for single message)"},
        "message": {"type": "string", "description": "Alternative: message field"},
        "membership_state": {"type": "string", "enum": ["active", "trial", "paused", "cancelled"], "description": "Filter audience (default: active)"},
        "send_now": {"type": "boolean", "description": "Send immediately or save as draft"}
    }
}

{
    "type": "object",
    "properties": {
        "overdue": {"type": "boolean", "description": "Only show overdue activities"},
        "res_model": {"type": "string", "description": "Filter by model (e.g. dojo.member)"}
    }
}

{
    "type": "object",
    "required": ["summary"],
    "properties": {
        "summary": {"type": "string", "description": "Activity description/summary"},
        "date_deadline": {"type": "string", "format": "date", "description": "Due date (YYYY-MM-DD)"},
        "activity_type": {"type": "string", "description": "Activity type: Todo, Call, Email, Meeting (default: Todo)"},
        "note": {"type": "string", "description": "Additional notes for the activity"},
        "member_name": {"type": "string", "description": "Link activity to a specific member"}
    }
}
